    <script>
      (function() {
        const script = document.currentScript;
        const core = script.closest('.ac6-core');
        const raw = core.querySelector('.raw-data').textContent;
        const dest = core.querySelector('.ac6-content');

        function esc(s) {
          return String(s)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
        }
        function fmt(s) {
          return esc(s).replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
        }

        const SECTION_LINE = /^(总览|战斗阶段|导弹-电子战对抗|先攻判定|蓝方行动|红方行动|我方行动|友方行动|敌方行动)$/;
        const SECTION_PREFIX = /^(资源结算|战斗总结)\b/;

        function isSectionHeader(t) {
          if (/[:：]$/.test(t)) return true;
          if (SECTION_LINE.test(t)) return true;
          if (SECTION_PREFIX.test(t)) return true;
          return false;
        }

        function renderSectionTitle(t) {
          const label = t.replace(/[:：]$/, '');
          return '<div class="ui-section-hdr"><span class="ui-hdr-prefix">::</span> ' + fmt(label) + '</div>';
        }

        function renderPipeRow(t) {
          const parts = t.split(' | ').map(function(p) { return p.trim(); }).filter(Boolean);
          var html = '';
          if (t.indexOf('武器:[') !== -1 || t.indexOf('武器:') !== -1) {
            html += '<div class="ui-tag-row-hint">UNIT.TELEMETRY // PIPELINE</div>';
          }
          html += '<div class="ui-data-row">';
          parts.forEach(function(p) {
            var c = p.indexOf(':');
            var z = p.indexOf('：');
            var idx = c === -1 ? z : (z === -1 ? c : Math.min(c, z));
            if (idx !== -1) {
              var k = p.substring(0, idx).trim();
              var v = p.substring(idx + 1).trim();
              html += '<div class="ui-tag"><span class="ui-tag-key">' + fmt(k) + '</span><span class="ui-tag-val">' + fmt(v) + '</span></div>';
            } else {
              html += '<div class="ui-tag"><span class="ui-tag-val">' + fmt(p) + '</span></div>';
            }
          });
          html += '</div>';
          return html;
        }

        var html = '';
        var lines = raw.split(/\r?\n/);

        lines.forEach(function(original) {
          var t0 = original.trim();
          if (!t0) {
            html += '<div class="ui-spacer"></div>';
            return;
