          if (/^\s{2,}/.test(original) && !/^-\s/.test(t0)) {
            html += '<div class="ui-text ui-text-continue">' + fmt(t0) + '</div>';
            return;
          }

          var t = t0.replace(/^\*\*\s*/, '').replace(/\s*\*\*$/, '');

          if (isSectionHeader(t)) {
            html += renderSectionTitle(t);
            return;
          }

          if (t.indexOf(' | ') !== -1) {
            html += renderPipeRow(t);
            return;
          }

          if (/^-\s/.test(t)) {
            html += '<div class="ui-list-item"><div class="ui-li-icon"></div><span class="ui-li-text">' + fmt(t.replace(/^-\s+/, '')) + '</span></div>';
            return;
