          var kvMatch = t.match(/^([^:：]+)[:：]\s+(.*)$/);
          if (kvMatch) {
            html += '<div class="ui-kv"><span class="ui-kv-key">' + fmt(kvMatch[1]) + '</span><span class="ui-kv-val">' + fmt(kvMatch[2]) + '</span></div>';
            return;
          }

          html += '<div class="ui-text">' + fmt(t0) + '</div>';
        });

        dest.innerHTML = html;
      })();

