      if (typeof ResizeObserver !== 'undefined') {
        var resizeObserver = new ResizeObserver(function() { updateHeight(); });
        resizeObserver.observe(document.body);
      }
      document.addEventListener('keydown', function(e) {
        var h = document.activeElement;
        if (h && h.classList.contains('ac6-header') && (e.key === 'Enter' || e.key === ' ')) {
          e.preventDefault();
          toggleCore(h);
        }
      });
    </script>
